1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	
5	const BASE_PREMIUMS: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	function calculateBasePremium(items: any[]): number {
17	  const componentCounts: Record<string, number> = {};
18	  let premium = 0;
19	  for (const item of items) {
20	    if (COMPONENT_TYPES.has(item.type)) {
21	      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
22	    } else {
23	      premium += BASE_PREMIUMS[item.type];
24	    }
25	  }
26	  for (const [type, count] of Object.entries(componentCounts)) {
27	    premium += count === 3 ? COMPONENT_BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
28	  }
29	  return premium;
30	}
31	
32	export function processScenario(scenario: any): any {
33	  const results = scenario.steps.map((step: any) => {
34	    const basePremium = calculateBasePremium(step.items);
35	    const premium = basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE + PROCESSING_FEE;
36	    return { premium };
37	  });
38	  return { results };
39	}
